import { useState } from 'react'
import { useQueryClient } from '@tanstack/react-query'
import {
  Box, Typography, Button, Paper, Table, TableBody, TableCell, TableContainer,
  TableHead, TableRow, IconButton, Tooltip, Dialog, DialogTitle, DialogContent,
  DialogActions, TextField, MenuItem, CircularProgress,
} from '@mui/material'
import AddIcon from '@mui/icons-material/Add'
import DeleteOutlineIcon from '@mui/icons-material/DeleteOutline'

// Generated by: npm run generate-api
import { useListLabs, useCreateLab, useDeleteLab, getListLabsQueryKey } from '../../api/labs/labs'
import { useListCompanies } from '../../api/companies/companies'
import { useAuthStore } from '../auth/authStore'
import { hasRole } from '../../types'

export default function LabsPage() {
  const queryClient = useQueryClient()
  const { profile } = useAuthStore()
  const canPickCompany = profile ? hasRole(profile.role, 'super_admin') : false

  const [open, setOpen] = useState(false)
  const [name, setName] = useState('')
  const [companyId, setCompanyId] = useState('')

  const { data: labsPage, isLoading } = useListLabs()
  const labs = labsPage?.items ?? []
  const { data: companiesPage } = useListCompanies()
  const companies = companiesPage?.items ?? []

  const { mutate: createLab, isPending: creating } = useCreateLab({
    mutation: {
      onSuccess: () => {
        queryClient.invalidateQueries({ queryKey: getListLabsQueryKey() })
        setOpen(false)
        setName('')
        setCompanyId('')
      },
    },
  })

  const { mutate: deleteLab } = useDeleteLab({
    mutation: {
      onSuccess: () => queryClient.invalidateQueries({ queryKey: getListLabsQueryKey() }),
    },
  })

  const handleCreate = () => {
    const cid = canPickCompany ? companyId : (profile?.lab?.company.id ?? '')
    if (!name.trim() || !cid) return
    createLab({ data: { name, company_id: cid } })
  }

  return (
    <Box sx={{ p: 3, height: '100%', overflow: 'auto' }}>
      <Box sx={{ display: 'flex', alignItems: 'center', mb: 3 }}>
        <Typography variant="h6" fontWeight={600} sx={{ flex: 1 }}>
          Labs
        </Typography>
        <Button variant="contained" startIcon={<AddIcon />} onClick={() => setOpen(true)}>
          New Lab
        </Button>
      </Box>

      {isLoading ? (
        <CircularProgress />
      ) : (
        <TableContainer component={Paper} elevation={1}>
          <Table size="small">
            <TableHead>
              <TableRow>
                <TableCell sx={{ fontWeight: 600 }}>Name</TableCell>
                <TableCell sx={{ fontWeight: 600 }}>Company</TableCell>
                <TableCell sx={{ fontWeight: 600 }}>Created</TableCell>
                <TableCell width={60} />
              </TableRow>
            </TableHead>
            <TableBody>
              {labs.length === 0 && (
                <TableRow>
                  <TableCell colSpan={4}>
                    <Typography variant="body2" color="text.secondary" textAlign="center" py={2}>
                      No labs yet.
                    </Typography>
                  </TableCell>
                </TableRow>
              )}
              {labs.map((lab) => {
                const company = companies.find((c) => c.id === lab.company_id)
                return (
                  <TableRow key={lab.id as string} hover>
                    <TableCell>{lab.name}</TableCell>
                    <TableCell>{company?.name ?? '—'}</TableCell>
                    <TableCell>{new Date(lab.created_at).toLocaleDateString()}</TableCell>
                    <TableCell>
                      <Tooltip title="Delete">
                        <IconButton
                          size="small"
                          color="error"
                          onClick={() => {
                            if (confirm(`Delete lab "${lab.name}"?`))
                              deleteLab({ labId: lab.id as string })
                          }}
                        >
                          <DeleteOutlineIcon fontSize="small" />
                        </IconButton>
                      </Tooltip>
                    </TableCell>
                  </TableRow>
                )
              })}
            </TableBody>
          </Table>
        </TableContainer>
      )}

      <Dialog open={open} onClose={() => setOpen(false)} maxWidth="xs" fullWidth>
        <DialogTitle>New Lab</DialogTitle>
        <DialogContent>
          <Box sx={{ display: 'flex', flexDirection: 'column', gap: 2, mt: 1 }}>
            <TextField
              autoFocus
              label="Lab name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              fullWidth
              size="small"
            />
            {canPickCompany && (
              <TextField
                select
                label="Company"
                value={companyId}
                onChange={(e) => setCompanyId(e.target.value)}
                fullWidth
                size="small"
              >
                {companies.map((c) => (
                  <MenuItem key={c.id as string} value={c.id as string}>
                    {c.name}
                  </MenuItem>
                ))}
              </TextField>
            )}
          </Box>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setOpen(false)}>Cancel</Button>
          <Button variant="contained" disabled={!name.trim() || creating} onClick={handleCreate}>
            Create
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  )
}
